[HttpGet("{productId:int}/Reviews")]
public IActionResult Reviews([FromRoute] int productId) {
    var product = context.Products
                        .Include(p => p.Reviews) // Include product with related reviews.
                        .SingleOrDefault(p => p.ProductId == productId);
    return View("Product",product);
}

 @section head_elements{
     @Html.Partial("_Rating")
 }
 
 @section content {
    <h2>Product reviews</h2>
    @foreach (var review in Model.Reviews) {
        <div class="col">
            <p>@review.ReviewText </p>
            <small class="text-muted">@review.UserName </small>
        </div>
    }
}